export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰沿著通往迷霧之森的小徑前進。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這條路他之前沒有走過，但與其他小徑類似，都是由碎石和泥土構成，兩旁是茂密的黑色森林。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白劍在手中散發著柔和的光芒，照亮了前方的道路。那股無形的拉扯力依然存在，引導著他的方向。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走了大約十分鐘後，李杰注意到周圍的環境開始發生變化。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這是...霧？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他放慢腳步，警戒地看著四周。淡淡的白色霧氣開始在森林中瀰漫，最初只是薄薄的一層，幾乎不影響視線。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但隨著他繼續前進，霧氣越來越濃。十五分鐘後，霧已經變得相當濃厚，能見度開始下降。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十分鐘...二十五分鐘...霧氣持續增強，像是一層厚重的白色帷幕，籠罩著整片森林。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這霧...越來越濃了...還好有這把劍照亮..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他握緊白劍，謹慎前進。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三十分鐘後，李杰終於來到了一個新的交叉口。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是一個四岔路口，四條道路在此交匯。但與之前那些狹窄的小徑不同，這裡的道路明顯寬闊許多，像是主要幹道。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "濃霧在這裡達到了頂峰，白茫茫的一片，能見度只剩下五到十米。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰只能勉強看清眼前的道路，再遠處的景物都被霧氣完全吞噬。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這霧...太濃了...什麼都看不清..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停下腳步，環顧四周。白劍的光芒在濃霧中顯得更加重要，成為了唯一可靠的光源。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在這時，白劍再次給出明確的指引。劍身突然向右傾斜，那股無形的力量堅定地拉扯著他的手臂，指向右側的道路。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "右邊嗎..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看向右側，但只能看到濃霧。他沒有猶豫，直接踏上了右側的寬闊道路。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這條道路比之前走過的都要寬闊，足以容納兩三個人並行，地面也更加平整，顯然是經常使用的主要道路。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但濃霧嚴重限制了視線，李杰只能看清眼前幾米的路面，周圍的樹木和景物都隱沒在白茫茫的霧海中，若隱若現。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只有白劍的光芒和腳下的道路，讓他能夠確認前進的方向。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰繼續前進，在濃霧中謹慎地邁步，腳步聲在寂靜的森林中迴盪。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又過了十五分鐘左右，前方的霧氣中隱約出現了一片較為開闊的區域。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "前面...好像有空地..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他放慢腳步，警戒地握緊劍。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "當他走進空地時，濃霧稍微薄了一些，能見度提升到十幾米，眼前的景象讓他心臟一沉。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "那是...！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他震驚地說。在空地中央，一個年輕女孩倒在地上，一動不動。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的身下有一大灘暗紅色的血跡，在白劍的光芒下泛著詭異的光澤。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "有人受傷了！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他立刻衝過去，跪在女孩身邊，仔細查看她的情況。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "女孩看起來二十歲左右，穿著一件淺米色的棉質連衣裙，裙擺輕輕搭在膝蓋上，露出纖細的小腿和一雙乾淨的白色帆布鞋。外面套著一件素色的女式外套。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "長長的黑髮散落在地上，她的臉色蒼白如紙，眼睛緊閉，沒有任何呼吸。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他伸手探向她的鼻息。沒有呼吸。身體已經開始變冷。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這張臉...我見過..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他緩緩放下手，看著女孩的臉。他努力回憶著。在這個詭異的世界裡，他見過的活人並不多。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他想起來了——在寂海車站的月台上，那個文靜的女孩。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她和那群大學生、還有那個沉穩的大叔、以及一個戴眼鏡的年輕男子一起下了車，走進了森林。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "是她...在寂海站下車的那個女孩..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低聲說。他的目光落在女孩的頸部，那裡有一道可怕的傷口。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是一道深深的切口，橫向劃過整個喉嚨。傷口從正面造成，像是有人面對面地一劍割開了她的咽喉。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "傷口的邊緣平整而乾淨，顯然是被極其鋒利的武器一擊造成的。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這傷口...是劍傷。從正面割喉...而且和之前那個女大生的傷口不太一樣..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他仔細觀察傷口，皺眉。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "之前在森林裡發現的那個活潑女大生，胸口有一個貫穿的傷口，是從正面刺入的。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這個女孩的傷口是橫向的切口，從正面割斷了喉嚨。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在這時，他的餘光瞥到了什麼。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "那裡還有人！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他猛然轉頭。在空地的另一側，靠近樹叢的地方，還有另一個人影倒在地上，臉朝下趴著。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "還有另一個人...！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他立刻站起身，跑向那個人影。他跑到那人身邊，毫不猶豫地抓住肩膀，用力將屍體翻過來。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "當他看清那張臉時，心中的不安更加強烈了。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這個人...也是在寂海站下車的..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他震驚地說。那是一個戴著眼鏡的年輕男子，看起來二十多歲，穿著整潔的襯衫和長褲。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他就是當時和那個文靜女孩、大學生們、以及沉穩大叔一起下車的那個人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "眼鏡已經掉在一旁，碎成了幾片。他的眼睛半睜著，眼神空洞而呆滯，嘴巴微微張開，像是想要說些什麼。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "也死了..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他探向他的鼻息。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "眼鏡男的胸口有一個巨大的傷口，鮮血早已凝固，將襯衫染成深紅色。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是一個貫穿性的傷口，從前胸直接刺入，貫穿了心臟。傷口的形狀和深度，顯然也是劍傷。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "兩個人...都被劍殺死了..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起身，環顧四周。他開始在空地上仔細搜索，試圖找到更多線索。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "地面上有凌亂的腳印，顯示這裡不久前發生過一場追逐或打鬥。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這些腳印..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他蹲下，仔細觀察腳印。他看到了幾行清晰的腳印。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "其中兩行應該是這兩個死者的——一行是女孩較小的腳印，一行是眼鏡男較大的腳印。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這兩行腳印都是從他來的方向——也就是從那個四岔路口的方向延伸過來的。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "除此之外，還有第三行腳印。那行腳印更深、更大，步伐沉穩而有力。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三行腳印同樣來自那個方向，但在這片空地上與前兩行腳印交匯後，繼續向前延伸——往迷霧之森中心的方向。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "兇手...就是留下這行腳印的人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著那行繼續向前的腳印，低聲說。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "他們在前往迷霧之森中心的路上被襲擊了...而兇手殺了他們之後，繼續往森林中心前進..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起身，看向腳印延伸的方向。他回想起自己走過來的路。濃霧中他沒有看到任何其他人，也沒有遇到任何危險。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在這時，手中的白劍再次震動起來。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "又來了..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看向白劍。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這次的震動比之前更加強烈，劍身散發的光芒也更加明亮，幾乎刺眼。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那股無形的力量更加強烈地拉扯著他的手臂，堅定地指向前方——迷霧之森中心的方向，與兇手腳印延伸的方向一致。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "白劍的反應更強了...它指引的方向...和兇手前進的方向一樣..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著劍，又看向那個方向，恍然大悟。他看了看地上兩具冰冷的屍體，又看了看白劍指引的方向和地上延伸的腳印。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "無論答案是什麼，有一件事是確定的——迷霧之森的中心，有什麼東西在等待著他，而那個兇手也在往那裡前進。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "既然你這麼想去...那我就跟你走到底。也許...我能在那裡找到兇手。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他握緊白劍，看向前方濃霧籠罩的道路。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他最後看了一眼地上的兩具屍體，深吸一口氣，轉身朝著白劍指引的方向前進。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是通往迷霧之森中心的道路，也是兇手前進的方向。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白劍的光芒在濃霧中更加明亮，像是一盞指路的明燈，引導著他走向未知的命運。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "不管前面有什麼...我都要弄清楚這一切。如果兇手也在那裡...我就用這把劍來對付他。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低聲，堅定地說。他的身影逐漸消失在濃霧的深處，只留下那兩具冰冷的屍體靜靜地躺在空地上。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白色的濃霧再次籠罩了一切，將所有的秘密都隱藏在其中。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "紫月依然高懸天空，透過霧氣投下微弱的光芒，見證著這片森林中的每一個秘密。" },
];
